const { Sequelize, DataTypes } = require('sequelize');
const fs = require('fs');
const path = require('path');

async function main() {
  const sequelize = new Sequelize({
    dialect: 'sqlite',
    storage: path.join(__dirname, 'database.sqlite'),
    logging: false,
  });

  // beforeConnect hook: asynchronously read password from token.txt
  sequelize.beforeConnect(async (config) => {
    const password = await fs.promises.readFile(
      path.join(__dirname, 'token.txt'),
      'utf8'
    );
    config.password = password.trim();
  });

  // Define User model
  const User = sequelize.define('User', {
    username: {
      type: DataTypes.STRING,
      allowNull: false,
    },
  });

  try {
    // Authenticate (triggers beforeConnect hook)
    await sequelize.authenticate();
    console.log(`Connected with password: ${sequelize.config.password}`);

    // Sync models to database
    await sequelize.sync();

    // Insert a new user
    await User.create({ username: 'alice' });

    console.log('User alice created successfully.');
  } catch (error) {
    console.error('Error:', error);
  } finally {
    await sequelize.close();
  }
}

main();

